    "title": "滑稽",
    "url": "movie-0604.html",
    "cover": "./4.jpg",
    "year": "2025",
    "type": "电影",
    "region": "意大利,法国",
    "category": "剧情家庭",
    "genre": "剧情,传记,喜剧",
